      options?.navigation?.routeToName?.(componentName, passProps || {}) || componentName || 'Unknown'

    if (currentRouteName) {
      const properties = options?.navigation?.routeToProperties?.(currentRouteName, passProps || {})
      posthog.screen(currentRouteName, properties)
    }
  })

