    this.capture('Application Opened', {
      ...properties,
      ...maybeAdd('url', initialUrl),
    })

    AppState.addEventListener('change', (state) => {
      if (state === 'active') {
        this.capture('Application Became Active')
      } else if (state === 'background') {
        this.capture('Application Backgrounded')
      }
    })
  }

